const p = path.join(Editor.Project.path, 'temp/logs/project.log');
const b = (typeof bytes === 'number' && bytes > 0) ? bytes : 8000;
const g = (typeof grep === 'string') ? grep : '';
const stat = fs.statSync(p);
const start = Math.max(0, stat.size - b);
const fd = fs.openSync(p, 'r');
const buf = Buffer.alloc(stat.size - start);
fs.readSync(fd, buf, 0, buf.length, start);
fs.closeSync(fd);
let lines = buf.toString('utf8').split(/\r?\n/);
if (g) lines = lines.filter(l => l.includes(g));
return lines.slice(-80).join('\n');
